{"file_text": "<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnSelected">
    <div class="channel-header">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    <div class="channel-description">@TruncateDescription(Channel.Description)</div>
</div>

@code {
    [Parameter, EditorRequired] public required Channel Channel { get; set; }
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnSelected { get; set; }

    private static string TruncateDescription(string description)
    {
        return description.Length > 40 ? string.Concat(description.AsSpan(0, 40), "…") : description;
    }
}
