.message-item {
    position: relative;
    padding: 8px 16px;
    border-radius: 4px;
    transition: background-color 0.1s;
}

.message-item:hover {
    background-color: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.author {
    font-weight: 700;
    font-size: 0.95rem;
    color: #1a1a1a;
}

.timestamp {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.93rem;
    color: #333;
    line-height: 1.5;
    word-break: break-word;
}

.reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    cursor: pointer;
    transition: background-color 0.15s;
}

.reaction-badge:hover {
    background: #e0e0f8;
    border-color: #aac;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 8px;
    font-size: 0.8rem;
    color: #1264a3;
    background: none;
    border: none;
    cursor: pointer;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -12px;
    right: 12px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.12);
    padding: 2px;
    z-index: 10;
