    background: none;
    border: none;
    cursor: pointer;
    border-radius: 4px;
    color: #555;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
    color: #111;
}

.emoji-picker {
    position: absolute;
    top: -12px;
    right: 160px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 8px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    padding: 4px;
    z-index: 11;
}

.emoji-btn {
    padding: 4px 6px;
    font-size: 1.2rem;
    background: none;
    border: none;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

