.channel-sidebar {
    display: flex;
    flex-direction: column;
    height: 100%;
    background-color: #2c2c3a;
    color: #e0e0e0;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px;
    border-bottom: 1px solid rgba(255, 255, 255, 0.1);
    flex-shrink: 0;
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
