@implements IAsyncDisposable
@inject IJSRuntime JS

<div class="message-area">
    <div class="area-header">
        @if (CurrentChannel is not null)
        {
            <h2># @CurrentChannel.Name</h2>
            <span class="header-description">@CurrentChannel.Description</span>
        }
    </div>

    <div class="message-list" @ref="messageListRef">
        @if (IsLoadingMore)
        {
            <div class="loading-indicator">Loading older messages…</div>
        }
        <div @ref="scrollSentinelRef" class="scroll-sentinel"></div>

        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ThreadReplyCount="GetThreadReplyCount(message.Id)"
                         OnOpenThread="() => OnOpenThread.InvokeAsync(message.Id)"
                         OnReact="(emoji) => OnReact.InvokeAsync((message.Id, emoji))" />
        }
    </div>

    <div class="message-input-area">
        <textarea class="message-input" rows="2" placeholder="Type a message…"
                  @bind="messageText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown" />
        <button class="send-btn" @onclick="SendMessage" disabled="@string.IsNullOrWhiteSpace(messageText)">
            Send
        </button>
    </div>
</div>

@code {
    [Parameter, EditorRequired] public required List<Message> Messages { get; set; }
    [Parameter] public Channel? CurrentChannel { get; set; }
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool IsLoadingMore { get; set; }
    [Parameter] public EventCallback<int> OnOpenThread { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReact { get; set; }
    [Parameter] public EventCallback<string> OnSendMessage { get; set; }
    [Parameter] public EventCallback OnLoadMore { get; set; }

    private ElementReference messageListRef;
    private ElementReference scrollSentinelRef;
    private IJSObjectReference? jsModule;
    private DotNetObjectReference<MessageArea>? dotNetRef;
    private string messageText = "";

    private int GetThreadReplyCount(int messageId) =>
        ThreadSummaries.TryGetValue(messageId, out var summary) ? summary.ReplyCount : 0;

    protected override async Task OnAfterRenderAsync(bool firstRender)
    {
        if (firstRender)
        {
            dotNetRef = DotNetObjectReference.Create(this);
            jsModule = await JS.InvokeAsync<IJSObjectReference>("import",
                "./Components/Pages/Chat/MessageArea.razor.js");
            await jsModule.InvokeVoidAsync("initScrollObserver", scrollSentinelRef, dotNetRef);
            await ScrollToBottom();
        }
    }

    [JSInvokable]
    public async Task OnScrolledToTop()
    {
        await OnLoadMore.InvokeAsync();
    }

    public async Task ScrollToBottom()
    {
        if (jsModule is not null)
        {
            await jsModule.InvokeVoidAsync("scrollToBottom", messageListRef);
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendMessage();
        }
    }

    private async Task SendMessage()
    {
        if (string.IsNullOrWhiteSpace(messageText)) return;

        var text = messageText.Trim();
        messageText = "";
        await OnSendMessage.InvokeAsync(text);
    }

    public async ValueTask DisposeAsync()
    {
        if (jsModule is not null)
        {
            try
            {
                await jsModule.InvokeVoidAsync("dispose");
                await jsModule.DisposeAsync();
            }
            catch (JSDisconnectedException)
            {
                // Circuit disconnected, ignore
            }
        }
        dotNetRef?.Dispose();
    }
}

