.message-area {
    display: flex;
    flex-direction: column;
    height: 100%;
    background: #fff;
    overflow: hidden;
}

.area-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.area-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
    color: #1a1a1a;
}

.header-description {
    font-size: 0.82rem;
    color: #777;
    margin-top: 2px;
    display: block;
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
}

.scroll-sentinel {
    height: 1px;
}

.loading-indicator {
    text-align: center;
    padding: 12px;
    color: #999;
    font-size: 0.85rem;
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #e0e0e0;
    background: #fafafa;
    flex-shrink: 0;
    align-items: flex-end;
}

.message-input {
    flex: 1;
    padding: 10px 12px;
    border: 1px solid #ccc;
    border-radius: 8px;
    font-size: 0.9rem;
    font-family: inherit;
    resize: none;
    outline: none;
    transition: border-color 0.15s;
}

.message-input:focus {
    border-color: #1264a3;
}

.send-btn {
    padding: 10px 20px;
    background-color: #1264a3;
    color: #fff;
    border: none;
    border-radius: 8px;
    font-weight: 600;
    font-size: 0.9rem;
    cursor: pointer;
    transition: background-color 0.15s;
    align-self: flex-end;
}

.send-btn:hover:not(:disabled) {
    background-color: #0d4f82;
}

.send-btn:disabled {
    opacity: 0.5;
    cursor: not-allowed;
}

let observer = null;

export function initScrollObserver(sentinel, dotNetRef) {
    if (observer) {
        observer.disconnect();
    }

    observer = new IntersectionObserver((entries) => {
        if (entries[0].isIntersecting) {
            dotNetRef.invokeMethodAsync('OnScrolledToTop');
        }
    }, { threshold: 0.1 });

    observer.observe(sentinel);
}

export function scrollToBottom(container) {
    if (container) {
        container.scrollTop = container.scrollHeight;
    }
}

export function dispose() {
    if (observer) {
        observer.disconnect();
        observer = null;
    }
}

