{"file_text": "<div class="thread-panel">
    <div class="thread-header">
        <h3>Thread</h3>
        <button class="close-btn" @onclick="OnClose" title="Close thread">✕</button>
    </div>

    @if (RootMessage is not null)
    {
        <div class="thread-root-message">
            <div class="root-author">@RootMessage.Author</div>
            <div class="root-content">@RootMessage.Content</div>
        </div>

        <div class="thread-divider">
            <span>@ThreadMessages.Count @(ThreadMessages.Count == 1 ? "reply" : "replies")</span>
        </div>
    }

    <div class="thread-messages">
        @foreach (var message in ThreadMessages)
        {
            <div class="thread-message">
                <div class="message-header">
                    <span class="author">@message.Author</span>
                    <span class="timestamp">@FormatRelativeTime(message.SentAt)</span>
                </div>
                <div class="message-content">@message.Content</div>
                @if (message.Reactions.Count > 0)
                {
                    <div class="reactions">
                        @foreach (var reaction in message.Reactions)
                        {
                            <span class="reaction-badge">@reaction.Emoji @reaction.Users.Count</span>
                        }
                    </div>
                }
            </div>
        }
    </div>

    <div class="reply-input-area">
        <textarea class="reply-input" rows="2" placeholder="Reply in thread…"
                  @bind="replyText" @bind:event="oninput"
                  @onkeydown="HandleKeyDown" />
        <button class="reply-btn" @onclick="SendReply" disabled="@string.IsNullOrWhiteSpace(replyText)">
            Reply
        </button>
    </div>
</div>

@code {
    [Parameter] public Message? RootMessage { get; set; }
    [Parameter, EditorRequired] public required List<Message> ThreadMessages { get; set; }
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnSendReply { get; set; }

    private string replyText = "";

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e is { Key: "Enter", ShiftKey: false })
        {
            await SendReply();
        }
    }

    private async Task SendReply()
    {
        if (string.IsNullOrWhiteSpace(replyText)) return;

        var text = replyText.Trim();
        replyText = "";
        await OnSendReply.InvokeAsync(text);
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt.ToUniversalTime();

        return diff.TotalSeconds switch
        {
            < 60 => "just now",
            < 3600 => $"{(int)diff.TotalMinutes} min ago",
            < 86400 => $"{(int)diff.TotalHours}h ago",
            < 604800 => $"{(int)diff.TotalDays}d ago",
            _ => sentAt.ToString("MMM d, yyyy")
        };
