    private bool isThreadOpen;
    private int? threadRootMessageId;
    private Message? threadRootMessage;
    private List<Message> threadMessages = [];
    private Dictionary<int, ThreadSummary> threadSummaries = new();

    private MessageArea? messageAreaRef;

    protected override async Task OnInitializedAsync()
    {
        channels = await ChatService.GetChannelsAsync();

        if (channels.Count > 0)
        {
            await SelectChannel(channels[0].Id);
        }
    }

    private async Task SelectChannel(int channelId)
    {
        if (selectedChannelId == channelId) return;

        selectedChannelId = channelId;
        currentChannel = channels.FirstOrDefault(c => c.Id == channelId);
        messageSkip = 0;
        hasMoreMessages = true;
        threadSummaries.Clear();
        CloseThread();

        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
        messageSkip = messages.Count;
        hasMoreMessages = messages.Count >= PageSize;

        await ChatService.MarkChannelReadAsync(channelId);

        // Update the unread count locally
        var idx = channels.FindIndex(c => c.Id == channelId);
        if (idx >= 0)
        {
            channels[idx] = channels[idx] with { UnreadCount = 0 };
        }

        StateHasChanged();

        if (messageAreaRef is not null)
        {
            await messageAreaRef.ScrollToBottom();
        }
    }

    private async Task LoadMoreMessages()
    {
        if (!hasMoreMessages || isLoadingMore || selectedChannelId is null) return;

        isLoadingMore = true;
        StateHasChanged();

        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messageSkip, PageSize);
        if (older.Count > 0)
        {
            messages.InsertRange(0, older);
            messageSkip += older.Count;
        }

        hasMoreMessages = older.Count >= PageSize;
        isLoadingMore = false;
    }

