    {
        if (selectedChannelId is null) return;

        var sent = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
        messages.Add(sent);
        messageSkip++;

        if (messageAreaRef is not null)
        {
            StateHasChanged();
            await messageAreaRef.ScrollToBottom();
        }
    }

