+@layout ChatLayout
+@rendermode InteractiveServer
+@inject IChatService ChatService
+
+<PageTitle>Chat</PageTitle>
+
+<div class="chat-container">
+    <div class="panel-sidebar">
+        <ChannelSidebar Channels="channels"
+                        SelectedChannelId="selectedChannelId"
+                        OnChannelSelected="SelectChannel" />
+    </div>
+
+    <div class="panel-messages @(isThreadOpen ? "" : "expanded")">
+        <MessageArea Messages="messages"
+                     CurrentChannel="currentChannel"
+                     ThreadSummaries="threadSummaries"
+                     IsLoadingMore="isLoadingMore"
+                     OnOpenThread="OpenThread"
+                     OnReact="HandleReaction"
+                     OnSendMessage="SendMessage"
+                     OnLoadMore="LoadMoreMessages"
+                     @ref="messageAreaRef" />
+    </div>
+
+    @if (isThreadOpen)
+    {
+        <div class="panel-thread">
+            <ThreadPanel RootMessage="threadRootMessage"
+                         ThreadMessages="threadMessages"
+                         OnClose="CloseThread"
+                         OnSendReply="SendThreadReply" />
+        </div>
+    }
+</div>
+
+@code {
+    private List<Channel> channels = [];
+    private int? selectedChannelId;
+    private Channel? currentChannel;
+    private List<Message> messages = [];
+    private int messageSkip;
+    private bool hasMoreMessages = true;
+    private bool isLoadingMore;
+    private const int PageSize = 30;
+
+    private bool isThreadOpen;
+    private int? threadRootMessageId;
+    private Message? threadRootMessage;
+    private List<Message> threadMessages = [];
+    private Dictionary<int, ThreadSummary> threadSummaries = new();
+
+    private MessageArea? messageAreaRef;
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0].Id);
+        }
+    }
+
+    private async Task SelectChannel(int channelId)
+    {
+        if (selectedChannelId == channelId) return;
+
+        selectedChannelId = channelId;
+        currentChannel = channels.FirstOrDefault(c => c.Id == channelId);
+        messageSkip = 0;
+        hasMoreMessages = true;
+        threadSummaries.Clear();
+        CloseThread();
+
+        messages = await ChatService.GetMessagesAsync(channelId, 0, PageSize);
+        messageSkip = messages.Count;
+        hasMoreMessages = messages.Count >= PageSize;
+
+        await ChatService.MarkChannelReadAsync(channelId);
+
+        // Update the unread count locally
+        var idx = channels.FindIndex(c => c.Id == channelId);
+        if (idx >= 0)
+        {
+            channels[idx] = channels[idx] with { UnreadCount = 0 };
+        }
+
+        StateHasChanged();
+
+        if (messageAreaRef is not null)
+        {
+            await messageAreaRef.ScrollToBottom();
+        }
+    }
+
+    private async Task LoadMoreMessages()
+    {
+        if (!hasMoreMessages || isLoadingMore || selectedChannelId is null) return;
+
+        isLoadingMore = true;
+        StateHasChanged();
+
+        var older = await ChatService.GetMessagesAsync(selectedChannelId.Value, messageSkip, PageSize);
+        if (older.Count > 0)
+        {
+            messages.InsertRange(0, older);
+            messageSkip += older.Count;
+        }
+
+        hasMoreMessages = older.Count >= PageSize;
+        isLoadingMore = false;
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (selectedChannelId is null) return;
+
+        var sent = await ChatService.SendMessageAsync(selectedChannelId.Value, content, null);
+        messages.Add(sent);
+        messageSkip++;
+
+        if (messageAreaRef is not null)
+        {
+            StateHasChanged();
+            await messageAreaRef.ScrollToBottom();
+        }
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootMessageId = messageId;
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        isThreadOpen = true;
+
+        var thread = await ChatService.GetThreadAsync(messageId);
+        // First item is the root message; the rest are replies
+        threadMessages = thread.Where(m => m.Id != messageId).ToList();
+
+        threadSummaries[messageId] = new ThreadSummary(
+            messageId,
+            threadMessages.Count,
+            threadMessages.Count > 0 ? threadMessages[^1].SentAt : DateTime.UtcNow
+        );
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootMessageId = null;
+        threadRootMessage = null;
+        threadMessages = [];
+    }
+
+    private async Task HandleReaction((int MessageId, string Emoji) args)
+    {
+        await ChatService.AddReactionAsync(args.MessageId, args.Emoji);
+
+        // Optimistically update the local message
+        var msg = messages.FirstOrDefault(m => m.Id == args.MessageId);
+        if (msg is not null)
+        {
+            var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == args.Emoji);
+            if (existing is not null)
+            {
+                if (!existing.Users.Contains("You"))
+                    existing.Users.Add("You");
+            }
+            else
+            {
+                msg.Reactions.Add(new Reaction(args.Emoji, ["You"]));
+            }
+        }
+    }
+
+    private async Task SendThreadReply(string content)
+    {
+        if (threadRootMessageId is null || selectedChannelId is null) return;
+
+        var reply = await ChatService.SendMessageAsync(
+            selectedChannelId.Value, content, threadRootMessageId.Value);
+        threadMessages.Add(reply);
+
+        threadSummaries[threadRootMessageId.Value] = new ThreadSummary(
+            threadRootMessageId.Value,
+            threadMessages.Count,
+            reply.SentAt
+        );
+    }
+}
+

